concept.syntax:
import kotlinx.coroutines.*

// runBlocking creates a coroutine scope
fun main() = runBlocking {
    launch {          // start a new coroutine
        delay(100L)   // suspend (non-blocking pause)
        println("World")
    }
    println("Hello") // runs immediately, before delay completes
}
// Output: Hello  World

